export function IntegrationsSection() {
	return (
		<div className="pt-3 pl-5">
			{/* Featured integrations */}
			<div className="space-y-0">
				{featured.map((fw) => {
					const customIcon = featuredIcons[fw.name];
					const fallbackIcon =
						frameworkIcons[fw.icon as keyof typeof frameworkIcons];
					const renderIcon = customIcon || fallbackIcon;
					return (
						<Link
							key={fw.name}
							href={fw.href}
							className="group flex items-center gap-3 py-2.5 border-b border-dashed border-foreground/[0.06] last:border-b-0 hover:bg-foreground/[0.02] -mx-2 px-2 transition-colors"
						>
							<span className="text-foreground/50 dark:text-foreground/35 group-hover:text-foreground/70 transition-colors [&_svg]:w-5 [&_svg]:h-5 shrink-0">
								{renderIcon?.()}
							</span>
							<span className="text-[13px] font-medium text-foreground/75 dark:text-foreground/60 group-hover:text-foreground/90 transition-colors shrink-0 w-20">
								{fw.name}
							</span>
							<span className="text-[11px] font-mono text-foreground/30 dark:text-foreground/20 group-hover:text-foreground/45 transition-colors truncate">
								{fw.snippet}
							</span>
							<svg
								className="h-3 w-3 opacity-0 group-hover:opacity-40 transition-opacity shrink-0 ml-auto"
								viewBox="0 0 10 10"
								fill="none"
							>
								<path
									d="M1 9L9 1M9 1H3M9 1V7"
									stroke="currentColor"
									strokeWidth="1.2"
								/>
							</svg>
						</Link>
					);
				})}
			</div>

			{/* More frameworks */}
			<div className="mt-4">
				<p className="text-[9px] font-mono uppercase tracking-widest text-foreground/30 dark:text-foreground/20 mb-2">
					+ {moreFrameworks.length} more
				</p>
				<div className="flex flex-wrap gap-1.5">
					{moreFrameworks.map((fw) => {
						const iconFn =
							frameworkIcons[fw.icon as keyof typeof frameworkIcons];
						return (
							<Link
								key={fw.name}
								href={fw.href}
								className="group inline-flex items-center gap-1.5 px-2 py-1 border border-foreground/[0.06] hover:border-foreground/[0.12] hover:bg-foreground/[0.03] transition-colors"
							>
								<span className="text-foreground/40 dark:text-foreground/25 group-hover:text-foreground/60 transition-colors [&_svg]:w-3 [&_svg]:h-3">
									{iconFn?.()}
								</span>
								<span className="text-[9px] font-mono text-foreground/40 dark:text-foreground/30 group-hover:text-foreground/60 transition-colors">
									{fw.name}
								</span>
							</Link>
						);
					})}
				</div>
			</div>
		</div>
	);
}

export function PluginEcosystem() {
	const half = Math.ceil(plugins.length / 2);
	const row1 = plugins.slice(0, half);
	const row2 = plugins.slice(half);

	return (
		<div>
			<Link
				href="/docs/plugins"
				className="flex items-center justify-between w-full mb-4 text-[10px] font-mono text-foreground/35 dark:text-foreground/50 hover:text-foreground/55 transition-colors uppercase tracking-wider border-b border-dashed border-foreground/[0.1] px-3 py-1.5 bg-foreground/[0.02] hover:bg-foreground/[0.04]"
			>
				<span className="text-xs text-foreground/85 dark:text-foreground/75">
					Plugin Ecosystem
				</span>
				browse all &rarr;
			</Link>

			<div className="relative overflow-hidden">
				{/* Row 1 — scrolls left */}
				<div className="flex animate-[marquee_40s_linear_infinite] mb-1.5">
					{[...row1, ...row1].map((plugin, i) => (
						<span
							key={`${plugin.name}-${i}`}
							className="shrink-0 inline-flex items-center gap-1.5 px-3 py-1.5 mr-1.5 text-[11px] text-foreground dark:text-foreground/90 border border-foreground/[0.06] rounded-sm cursor-default whitespace-nowrap"
						>
							{plugin.name}
							<span className="text-[7px] font-mono uppercase tracking-wider text-foreground/50 ">
								{categoryLabels[plugin.category]}
							</span>
						</span>
					))}
				</div>

				{/* Row 2 — scrolls right */}
				<div className="flex animate-[marquee-reverse_45s_linear_infinite]">
					{[...row2, ...row2].map((plugin, i) => (
						<span
							key={`${plugin.name}-${i}`}
							className="shrink-0 inline-flex items-center gap-1.5 px-3 py-1.5 mr-1.5 text-[11px] text-foreground dark:text-foreground/90 border border-foreground/[0.06] rounded-sm cursor-default whitespace-nowrap"
						>
							{plugin.name}
							<span className="text-[7px] font-mono uppercase tracking-wider text-foreground/50 ">
								{categoryLabels[plugin.category]}
							</span>
						</span>
					))}
				</div>

				{/* Side fades */}
				<div className="absolute inset-y-0 left-0 w-12 bg-gradient-to-r from-background to-transparent pointer-events-none" />
				<div className="absolute inset-y-0 right-0 w-12 bg-gradient-to-l from-background to-transparent pointer-events-none" />
			</div>
		</div>
	);
}

